fun main() {
    // ---- Basic lambda syntax ----
    val greet: (String) -> String = { name -> "Hello, $name!" }
    println(greet("Kotlin-chan"))

    // ---- Lambda with implicit 'it' ----
    val greet2: (String) -> String = { "Hello, $it!" }
    println(greet2("Java-chan"))

    // ---- Lambda with multiple parameters ----
    val add: (Int, Int) -> Int = { a, b -> a + b }
    println("3 + 5 = ${add(3, 5)}")

    // ---- Lambda with no parameters ----
    val sayHello: () -> String = { "Hello, world!" }
    println(sayHello())

    // ---- Lambda with unit return ----
    val printMessage: (String) -> Unit = { message -> println("MSG: $message") }
    printMessage("This is a message")

    // ---- Lambda as parameter ----
    fun repeat(times: Int, action: (Int) -> Unit) {
        for (i in 1..times) {
            action(i)
        }
    }

    repeat(3) { println("Iteration $it") }

    // ---- Lambda with receiver ----
    val buildString: StringBuilder.() -> Unit = {
        append("Hello")
        append(", ")
        append("World!")
    }
    val result = StringBuilder().apply(buildString).toString()
    println("Built string: $result")

    // ---- Lambda returning lambda ----
    fun multiplier(factor: Int): (Int) -> Int {
        return { number -> number * factor }
    }

    val double = multiplier(2)
    val triple = multiplier(3)
    println("Double 5: ${double(5)}")
    println("Triple 5: ${triple(5)}")

    // ---- Lambda with underscore for unused parameter ----
    val printNumber: (Int, String) -> Unit = { _, message ->
        println("Message: $message")
    }
    printNumber(100, "Hello")

    // ---- Lambda with destructuring ----
    data class User(val name: String, val age: Int)
    val users = listOf(User("Alice", 25), User("Bob", 30))

    users.forEach { (name, age) ->
        println("$name is $age years old")
    }

    // ---- Lambda type aliases ----
    typealias StringTransformer = (String) -> String

    val toUpper: StringTransformer = { it.uppercase() }
    val toLower: StringTransformer = { it.lowercase() }

    println("HELLO -> ${toUpper("hello")}")
    println("WORLD -> ${toLower("WORLD")}")
}

